CREATE OR REPLACE VIEW vr_wef_mar_by_day (membership_no, member_name, spouse_name, marry_date, paid_date, total_receive, remark, operate_date, approve_date, wef_type, bank_acc_no, money_type_id, requestment_no, return_status) AS select sc_wef_req.membership_no,
       pka_com_function.fp_get_member_name(sc_wef_req.membership_no) as member_name,
       sc_mem_m_ucf_prename.prename||' '||first_name||' '||last_surname as spouse_name,
       sc_wef_req_mar.mar_date as marry_date,
       (select max(paid_date) FROM sc_fin_money_return where sc_wef_req.requestment_no = sc_fin_money_return.refno1) as paid_date,
       sc_wef_req.total_receive,
       sc_wef_req_mar.remark,
       sc_wef_req.operate_date,
       sc_wef_req.approve_date,
       sc_wef_req.wef_type,
       sc_wef_req.bank_acc_no,
       sc_wef_req.money_type_id,
       sc_wef_req.requestment_no,
       sc_fin_money_return.return_status
from sc_wef_req,sc_wef_req_mar,sc_mem_m_ucf_prename,sc_fin_money_return
where sc_wef_req.requestment_no = sc_wef_req_mar.requestment_no
and sc_wef_req_mar.prename = sc_mem_m_ucf_prename.prename_code
and sc_wef_req.requestment_no = sc_fin_money_return.refno1
and sc_fin_money_return.cancel_status = '0'
and sc_wef_req.cancel_status = '0'
and sc_wef_req.approve_status = '1'
and sc_wef_req.wef_type = 'MAR';

